#include <stdlib.h>
#include <stdio.h>
#include <math.h>
#include <cuda_runtime.h>

#define fp double
#define NUMBER_PAR_PER_BOX 100
#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct {
    fp x, y, z;
} THREE_VECTOR;

typedef struct {
    fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str {
    int x, y, z;
    int number;
    long offset;
} nei_str;

typedef struct box_str {
    int x, y, z;
    int number;
    long offset;
    int nn;
    nei_str nei[26];
} box_str;

typedef struct par_str {
    fp alpha;
} par_str;

typedef struct dim_str {
    int cur_arg;
    int arch_arg;
    int cores_arg;
    int boxes1d_arg;
    long number_boxes;
    long box_mem;
    long space_elem;
    long space_mem;
    long space_mem2;
} dim_str;

#include "./../util/timer/timer.h"

__global__ void kernel_gpu(
    par_str par,
    dim_str dim,
    box_str* box,
    FOUR_VECTOR* rv,
    fp* qv,
    FOUR_VECTOR* fv)
{
    fp alpha = par.alpha;
    fp a2 = 2.0 * alpha * alpha;

    int l = blockIdx.x;
    if (l >= dim.number_boxes) return;

    long first_i = box[l].offset;
    FOUR_VECTOR* rA = &rv[first_i];
    FOUR_VECTOR* fA = &fv[first_i];

    for (int k = 0; k < (1 + box[l].nn); k++) {
        int pointer;
        if (k == 0) {
            pointer = l;
        } else {
            pointer = box[l].nei[k-1].number;
        }

        long first_j = box[pointer].offset;
        FOUR_VECTOR* rB = &rv[first_j];
        fp* qB = &qv[first_j];

        for (int i = 0; i < NUMBER_PAR_PER_BOX; i++) {
            FOUR_VECTOR fA_i = fA[i];
            FOUR_VECTOR rA_i = rA[i];

            for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                FOUR_VECTOR rB_j = rB[j];
                fp qB_j = qB[j];

                fp r2 = rA_i.v + rB_j.v - DOT(rA_i, rB_j);
                fp u2 = a2 * r2;
                fp vij = exp(-u2);
                fp fs = 2.0 * vij;

                THREE_VECTOR d;
                d.x = rA_i.x - rB_j.x;
                d.y = rA_i.y - rB_j.y;
                d.z = rA_i.z - rB_j.z;

                fp fxij = fs * d.x;
                fp fyij = fs * d.y;
                fp fzij = fs * d.z;

                fA_i.v += qB_j * vij;
                fA_i.x += qB_j * fxij;
                fA_i.y += qB_j * fyij;
                fA_i.z += qB_j * fzij;
            }
            fA[i] = fA_i;
        }
    }
}

void kernel_cpu(par_str par,
                dim_str dim,
                box_str* box,
                FOUR_VECTOR* rv,
                fp* qv,
                FOUR_VECTOR* fv)
{
    long long time0 = get_time();
    long long time1 = get_time();
    long long time2 = get_time();
    long long time3 = get_time();

    fp alpha = par.alpha;
    fp a2 = 2.0 * alpha * alpha;

    time3 = get_time();

    box_str* box_d;
    FOUR_VECTOR* rv_d;
    fp* qv_d;
    FOUR_VECTOR* fv_d;

    cudaMalloc(&box_d, dim.box_mem);
    cudaMalloc(&rv_d, dim.space_mem);
    cudaMalloc(&qv_d, dim.space_mem2);
    cudaMalloc(&fv_d, dim.space_mem);

    cudaMemcpy(box_d, box, dim.box_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(rv_d, rv, dim.space_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(qv_d, qv, dim.space_mem2, cudaMemcpyHostToDevice);
    cudaMemcpy(fv_d, fv, dim.space_mem, cudaMemcpyHostToDevice);

    time2 = get_time();

    dim3 blockDim(NUMBER_PAR_PER_BOX, 1, 1);
    dim3 gridDim(dim.number_boxes, 1, 1);

    kernel_gpu<<<gridDim, blockDim>>>(par, dim, box_d, rv_d, qv_d, fv_d);

    cudaDeviceSynchronize();

    cudaMemcpy(fv, fv_d, dim.space_mem, cudaMemcpyDeviceToHost);

    long long time4 = get_time();

    printf("Time spent in different stages of GPU KERNEL:\n");
    printf("%15.12f s, %15.12f % : GPU: VARIABLES\n", (float)(time1-time0)/1000000, (float)(time1-time0)/(float)(time4-time0)*100);
    printf("%15.12f s, %15.12f % : GPU: SET DEVICE\n", (float)(time2-time1)/1000000, (float)(time2-time1)/(float)(time4-time0)*100);
    printf("%15.12f s, %15.12f % : GPU: INPUTS\n", (float)(time3-time2)/1000000, (float)(time3-time2)/(float)(time4-time0)*100);
    printf("%15.12f s, %15.12f % : GPU: KERNEL\n", (float)(time4-time3)/1000000, (float)(time4-time3)/(float)(time4-time0)*100);

    printf("Total time:\n");
    printf("%.12f s\n", (float)(time4-time0)/1000000);

    cudaFree(box_d);
    cudaFree(rv_d);
    cudaFree(qv_d);
    cudaFree(fv_d);
}

#ifdef __cplusplus
}
#endif

