                box_cpu[nh].x = k;
                box_cpu[nh].y = j;
                box_cpu[nh].z = i;
                box_cpu[nh].number = nh;
                box_cpu[nh].offset = nh * NUMBER_PAR_PER_BOX;
                box_cpu[nh].nn = 0;

                for(int l=-1; l<2; l++){
                    for(int m=-1; m<2; m++){
                        for(int n=-1; n<2; n++){
                            if(((i+l)>=0 && (j+m)>=0 && (k+n)>=0) && ((i+l)<dim_cpu.boxes1d_arg && (j+m)<dim_cpu.boxes1d_arg && (k+n)<dim_cpu.boxes1d_arg) && (l==0 && m==0 && n==0)==false){
                                box_cpu[nh].nei[box_cpu[nh].nn].x = (k+n);
